import React, { useState } from "react";
import CategoryModal from "./CategoryModal"; // Переконайся, що шлях правильний

const TaskCategories = ({ onGoBack }) => {
  // 1. Стан для відображення модального вікна
  const [isModalOpen, setIsModalOpen] = useState(false);

  // 2. Стан для даних (щоб ми могли додавати нові елементи)
  const [statusData, setStatusData] = useState([
    { id: 1, name: "Completed" },
    { id: 2, name: "In Progress" },
    { id: 3, name: "Not Started" },
  ]);

  const [priorityData, setPriorityData] = useState([
    { id: 1, name: "Extreme" },
    { id: 2, name: "Moderate" },
    { id: 3, name: "Low" },
  ]);

  // 3. Функція для створення нової категорії
  const handleCreateCategory = (name) => {
    // Тут можна додати логіку визначення, куди саме додавати (в статус чи пріоритет)
    // Поки що для прикладу додамо в статус:
    const newCategory = {
      id: Date.now(), // Тимчасовий ID
      name: name,
    };
    setStatusData([...statusData, newCategory]);
    console.log("Додано нову категорію:", name);
  };

  const TableSection = ({ title, data, addLabel }) => (
    <div className="category-section">
      <div className="category-header">
        <h3 className="category-title-text">{title}</h3>
        {/* Відкриваємо модалку при кліку на "Add" всередині таблиці */}
        <button
          className="add-sub-category"
          onClick={() => setIsModalOpen(true)}
        >
          <svg className="icon">
            <use xlinkHref="images/icons/dashboard-icons.svg#icon-plus"></use>
          </svg>{" "}
          {addLabel}
        </button>
      </div>

      <div className="table-container">
        <table className="task-table">
          <thead>
            <tr>
              <th className="col-sn">SN</th>
              <th className="col-name">{title}</th>
              <th className="col-action">Action</th>
            </tr>
          </thead>
          <tbody>
            {data.map((item, index) => (
              <tr key={item.id}>
                <td>{index + 1}</td>
                <td className="name-cell">{item.name}</td>
                <td className="action-cell">
                  <button className="btn-edit">
                    <span className="icon">
                      <svg className="icon">
                        <use xlinkHref="images/icons/my-task-icons.svg#icon-edit"></use>
                      </svg>
                    </span>
                    Edit
                  </button>
                  <button className="btn-delete">
                    <span className="icon">
                      <svg className="icon">
                        <use xlinkHref="images/icons/my-task-icons.svg#icon-delete"></use>
                      </svg>
                    </span>
                    Delete
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );

  return (
    <div className="task-categories-page">
      <div className="task-border">
        <div className="categories-card">
          <div className="categories-main-header">
            <h2>Task Categories</h2>
            <button className="go-back-link" onClick={onGoBack}>
              Go Back
            </button>
          </div>

          {/* Головна кнопка "Add Category" теж відкриває модалку */}
          <button
            className="add-category-btn"
            onClick={() => setIsModalOpen(true)}
          >
            Add Category
          </button>

          <TableSection
            title="Task Status"
            data={statusData}
            addLabel="Add Task Status"
          />
          <TableSection
            title="Task Priority"
            data={priorityData}
            addLabel="Add New Priority"
          />
        </div>
      </div>

      {/* 4. Додаємо саме модальне вікно в кінець компонента */}
      <CategoryModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onCreate={handleCreateCategory}
      />
    </div>
  );
};

export default TaskCategories;
